using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

// --- Build the chat client through MEAI abstraction ---
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient("gpt-4o-mini-2024-07-18")
    .AsIChatClient();

// --- Instantiate the tools ---
var notebook = new Notebook();
var webSearch = new WebSearchTool();

// --- Create the agent via Microsoft Agent Framework ---
var agent = new ChatClientAgent(chatClient,
    "ResearchAgent",
    """
    You are a research assistant. When the user gives you a topic:
    1. Search the web for relevant information (make 2-3 searches with different queries).
    2. Save the most important findings as notes.
    3. After gathering enough information, produce a concise summary of your findings,
       citing the sources you found.
    Always save notes before summarizing so nothing is lost.
    """)
{
    Tools = [.. AIFunctionFactory.Create(webSearch), .. AIFunctionFactory.Create(notebook)],
};

// --- Run the agent loop ---
Console.WriteLine("🔍 Research Agent");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();

    var history = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and summarize your findings: {topic}"),
    };

    var options = new AgentInvokeOptions { MaximumIterations = 15 };

    Console.WriteLine("\nResearching…\n");

    await foreach (var message in agent.InvokeStreamingAsync(history, options))
    {
        if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
        {
            Console.Write(message.Text);
        }
    }

    Console.WriteLine("\n");

    if (notebook.Notes.Count > 0)
    {
        Console.WriteLine($"📝 {notebook.Notes.Count} note(s) saved during research.\n");
    }
}

// ──────────────────────────────────────────────
//  Tool: Web Search (uses Bing via scraping-free API or falls back to a summary)
// ──────────────────────────────────────────────
sealed class WebSearchTool
{
    private static readonly HttpClient Http = new();

    [Description("Search the web for information on a query. Returns a list of result titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_redirect=1";
            var response = await Http.GetFromJsonAsync<JsonElement>(url);

            var results = new List<string>();

            // Abstract (main answer)
            var abstractText = response.GetProperty("Abstract").GetString();
            var abstractUrl = response.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"**{response.GetProperty("Heading").GetString()}**\n{abstractText}\nSource: {abstractUrl}");
            }

            // Related topics
            if (response.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var link = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add($"- {text}\n  URL: {link}");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : $"No detailed results found for \"{query}\". Try rephrasing.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

// ──────────────────────────────────────────────
//  Tool: Notebook (in-memory note taking)
// ──────────────────────────────────────────────
sealed class Notebook
{
    public List<string> Notes { get; } = [];

    [Description("Save a research note. Use this to record an important finding or fact.")]
    public string SaveNote(
        [Description("The note content to save")] string content)
    {
        Notes.Add(content);
        Console.WriteLine($"  📝 Note #{Notes.Count} saved.");
        return $"Note #{Notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", Notes.Select((n, i) => $"Note #{i + 1}: {n}"));
    }

    public void Clear() => Notes.Clear();
}

