using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

// --- Instantiate the tools ---
var notebook = new Notebook();
var webSearch = new WebSearchTool();

// Build tool list from annotated methods
var tools = new List<AITool>();
tools.AddRange(CreateToolsFromInstance(webSearch));
tools.AddRange(CreateToolsFromInstance(notebook));

// --- Build the chat client through MEAI abstraction ---
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient("gpt-4o-mini-2024-07-18")
    .AsIChatClient();

// --- Create the agent via Microsoft Agent Framework ---
var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: """
        You are a research assistant. When the user gives you a topic:
        1. Search the web for relevant information (make 2-3 searches with different queries).
        2. Save the most important findings as notes.
        3. After gathering enough information, produce a concise summary of your findings,
           citing the sources you found.
        Always save notes before summarizing so nothing is lost.
        """,
    id: "research-agent-01",
    tools: tools);

// --- Interactive loop ---
Console.WriteLine("🔍 Research Agent");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();
    Console.WriteLine("\nResearching…\n");

    var response = await agent.RunAsync(
        $"Research the following topic and summarize your findings: {topic}",
        session: null);

    Console.WriteLine(response.Text);
    Console.WriteLine();

    if (notebook.Notes.Count > 0)
    {
        Console.WriteLine($"📝 {notebook.Notes.Count} note(s) saved during research.\n");
    }
}

// --- Helper: create AIFunction tools from all [Description]-annotated public methods ---
static List<AITool> CreateToolsFromInstance(object instance)
{
    var result = new List<AITool>();
    foreach (var method in instance.GetType().GetMethods(
        System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.DeclaredOnly))
    {
        if (method.GetCustomAttributes(typeof(DescriptionAttribute), false).Length > 0)
        {
            result.Add(AIFunctionFactory.Create(method, instance));
        }
    }

    return result;
}

